const mobileMenuToggle=document.getElementById("mobileMenuToggle"),navMenu=document.getElementById("navMenu"),navLinks=document.querySelectorAll(".nav-link");mobileMenuToggle.addEventListener("click",()=>{mobileMenuToggle.classList.toggle("active"),navMenu.classList.toggle("active"),document.body.style.overflow=navMenu.classList.contains("active")?"hidden":"auto"}),navLinks.forEach(e=>{e.addEventListener("click",()=>{mobileMenuToggle.classList.remove("active"),navMenu.classList.remove("active"),document.body.style.overflow="auto"})});const animateCounter=(e,t,n=2e3)=>{let s=0,a=t/(n/16),o=()=>{(s+=a)<t?(e.textContent=Math.floor(s),requestAnimationFrame(o)):e.textContent=t};o()},observeStats=()=>{let e=document.querySelectorAll(".stat-number"),t=new IntersectionObserver(e=>{e.forEach(e=>{if(e.isIntersecting&&!e.target.classList.contains("counted")){e.target.classList.add("counted");let t=parseInt(e.target.textContent);animateCounter(e.target,t)}})},{threshold:.5});e.forEach(e=>t.observe(e))};window.addEventListener("load",observeStats);const observeElements=()=>{let e=document.querySelectorAll(".benefit-card, .gallery-item"),t=new IntersectionObserver(e=>{e.forEach((e,t)=>{e.isIntersecting&&setTimeout(()=>{e.target.style.opacity="1",e.target.style.transform="translateY(0)"},100*t)})},{threshold:.1,rootMargin:"0px 0px -100px 0px"});e.forEach(e=>{e.style.opacity="0",e.style.transform="translateY(30px)",e.style.transition="opacity 0.6s ease-out, transform 0.6s ease-out",t.observe(e)})};window.addEventListener("load",()=>{observeElements(),document.body.classList.add("loaded")});